import React, { useState } from 'react';

const App = () => {
  const [tokenCount, setTokenCount] = useState({
    tokens: [10, 20, 30],
    credits: 100
  });
  const [searchQuery, setSearchQuery] = useState('');
  const [prompt, setPrompt] = useState('');

  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className="grid grid-cols-3 gap-4">
        {tokenCount.tokens.map((token, index) => (
          <div key={index} className="bg-[#B7D7CD] p-4 rounded">
            <span className="text-lg">Token {index + 1}</span>
            <button className="bg-[#C06C88] p-2 rounded" onClick={() => setTokenCount({ ...tokenCount, tokens: [...tokenCount.tokens.slice(0, index), tokenCount.tokens[index] + 1, ...tokenCount.tokens.slice(index + 1)] })}>+</button>
            <button className="bg-[#C06C88] p-2 rounded" onClick={() => setTokenCount({ ...tokenCount, tokens: [...tokenCount.tokens.slice(0, index), Math.max(tokenCount.tokens[index] - 1, 0), ...tokenCount.tokens.slice(index + 1)] })}>-</button>
          </div>
        ))}
      </div>
      <input type="search" className="bg-[#B7D7CD] p-2 w-full rounded" value={searchQuery} onChange={e => setSearchQuery(e.target.value)} placeholder="Search"/>
      <div className="bg-[#B7D7CD] p-4 rounded">
        <h2 className="text-lg">Credits Manager</h2>
        <button className="bg-[#C06C88] p-2 rounded" onClick={() => setTokenCount({ ...tokenCount, credits: tokenCount.credits + 1 })}>Generate Token</button>
        <p className="text-lg">Credits: {tokenCount.credits}</p>
        <input type="text" className="bg-[#B7D7CD] p-2 w-full rounded" value={prompt} onChange={e => setPrompt(e.target.value)} placeholder="Enter Prompt"/>
        <p className="text-lg">Characters: {prompt.length}</p>
      </div>
    </div>
  );
};

export default App;
